mapper.select:
		SELECT job_no AS jobNo
		           , j.title
                   , p.project_name AS projectName
                   , p.project_code
                   , j.job_status_no
                   , j.job_type_no
                   , j.priority
		           , FN_GET_JOB_STATUS(j.job_status_no) AS job_status
                   , FN_GET_JOB_TYPE(j.job_type_no) AS job_type
                   , FN_GET_CODE_NAME(j.priority) AS priority_name
		           , j.manager_id
		           , j.files_no
		           , j.progress
		           , j.start_date
		           , j.end_date
		           , u.username
		FROM job j
                 JOIN project p 
                 ON j.project_no = p.project_no
                 JOIN users u
                 ON j.user_id = u.user_id
        WHERE p.project_code = #{projectCode}

          AND j.user_id = #{userId}


          AND j.job_no = #{jobNo}


          AND j.title LIKE '%' || #{title} || '%'


          AND j.manager_id = #{userId}


          AND j.job_status_no = #{jobStatusNo}


          AND j.job_type_no = #{jobTypeNo}


          AND j.priority = #{priority}


          AND j.progress = #{progress}


          AND j.start_date = #{startDate}


          AND j.end_date = #{endDate}

mapper.insert:
INSERT INTO HISTORY (
history_no
, change_comment
, user_id
, history_date
, delete_date
, job_no
) VALUES (
HISTORY_SEQ.NEXTVAL
, #{changeComment}
, #{historyUserId}
, CURRENT_TIMESTAMP
, #{deleteDate}
, #{jobNo}
)
